package net.unit8.souther.runtime;

import java.util.List;
import java.util.Set;

/** Set helpers the generated bytecode calls. A Set is unordered with no duplicates, compared by the
 *  elements' value equality (spec collections, ADR-0009). A {@code Set} value is a
 *  {@link PersistentHashSet} (CHAMP, structural sharing): every operation returns a fresh set that
 *  shares structure with its input in O(log n) and never mutates it. Iteration order is a
 *  deterministic, implementation-defined hash order (not first-seen order), stable for the same
 *  element set so {@code toList} / encode stay reproducible. This class is Raoh-free; {@link #fromList}
 *  is also the dedup a Set decoder maps a list through, and keeps its exact {@code (List) -> Set}
 *  signature because a Set decoder resolves it by method handle. */
public final class Sets {

    private Sets() {}

    /** The empty set; its element type is fixed by context (the {@code Set.empty} built-in). */
    public static Set<?> empty() {
        return PersistentHashSet.empty();
    }

    public static <T> Set<T> singleton(T value) {
        return PersistentHashSet.ofSingle(value);
    }

    public static <T> Set<T> insert(T value, Set<T> s) {
        return PersistentHashSet.from(s).with(value);
    }

    /** {@code s} without {@code value}; {@code s} unchanged when absent. The {@code contains} probe
     *  returns the original set untouched when the value is absent, avoiding normalizing a still-JDK
     *  input set into a {@code PersistentHashSet} for a no-op removal. */
    public static <T> Set<T> remove(T value, Set<T> s) {
        if (!s.contains(value)) {
            return s;
        }
        return PersistentHashSet.from(s).without(value);
    }

    public static boolean contains(Object value, Set<?> s) {
        return s.contains(value);
    }

    public static <T> Set<T> union(Set<T> a, Set<T> b) {
        return PersistentHashSet.union(a, b);
    }

    public static <T> Set<T> intersect(Set<T> a, Set<T> b) {
        return PersistentHashSet.intersect(a, b);
    }

    /** The elements of {@code a} that are not in {@code b}. */
    public static <T> Set<T> difference(Set<T> a, Set<T> b) {
        return PersistentHashSet.difference(a, b);
    }

    public static boolean isEmpty(Set<?> s) {
        return s.isEmpty();
    }

    public static long size(Set<?> s) {
        return s.size();
    }

    public static <T> List<T> toList(Set<T> s) {
        return PersistentVector.from(s);
    }

    /** A set from a list, dropping duplicates. Also the map a derived Set decoder applies to the list
     *  it decodes. */
    public static <T> Set<T> fromList(List<T> xs) {
        return PersistentHashSet.from(xs);
    }
}
